CREATE OR REPLACE PROCEDURE process_customer_order (
    p_customer_id   IN NUMBER,
    p_order_amount  IN NUMBER,
    p_order_type    IN VARCHAR2,
    p_region        IN VARCHAR2
)
IS
    v_customer_name      VARCHAR2(200);
    v_customer_status    VARCHAR2(50);
    v_discount           NUMBER := 0;
    v_tax                NUMBER := 0;
    v_final_amount       NUMBER := 0;
    v_credit_limit       NUMBER := 0;
    v_order_count        NUMBER := 0;
    v_sql                VARCHAR2(4000);
    v_flag               VARCHAR2(10);
BEGIN
    DBMS_OUTPUT.PUT_LINE('Procedure started');
    SELECT *
    INTO v_customer_id, v_customer_name, v_customer_status, v_credit_limit
    FROM (
        SELECT customer_id, customer_name, status, credit_limit
        FROM customers
        WHERE customer_id = p_customer_id
    );
    IF p_region = 'INDIA' THEN
        v_tax := p_order_amount * 18 / 100;
    ELSIF p_region = 'USA' THEN
        v_tax := p_order_amount * 7 / 100;
    ELSE
        v_tax := p_order_amount * 10 / 100;
    END IF;
    v_sql := 'UPDATE customers SET last_order_amount = ' || p_order_amount ||
             ' WHERE customer_id = ' || p_customer_id;
    EXECUTE IMMEDIATE v_sql;
    COMMIT;
EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('Some error occurred: ' || SQLERRM);
        ROLLBACK;
END;
/

